import React, { useState } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Image } from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { SvgXml } from 'react-native-svg';
import menuLeftAltSvg from '../public/img/menu-left-alt.svg';

const styles = StyleSheet.create({
  headerContainer: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    alignItems: 'center',
    height: 60,
    backgroundColor: '#f2f2f2',
    paddingTop: 20,
    paddingHorizontal: 10,
    borderBottomWidth: 1,
    borderBottomColor: '#ccc',
  },
  navItem: {
    fontSize: 13,
    fontWeight: 'bold',
    marginHorizontal: 10,
    marginVertical: 5,
    padding: 5,
    borderRadius: 5,
    backgroundColor: '#fff',
    color: '#333',
  },
  menuImage: {
    width: 20,
    height: 20,
    resizeMode: 'contain',
  },
});

function Menu() {
  const [isOpen, setIsOpen] = useState(false);
  const navigation = useNavigation();

  const handlePokemonPress = (pokemonId) => {
    setIsOpen(!isOpen)
    navigation.navigate('PokedexList', { id: pokemonId });
  };

  const toggleMenu = () => {
    setIsOpen(!isOpen);
  };

  return (
    <View style={styles.headerContainer}>
      {isOpen && (
        <>
          <TouchableOpacity onPress={() => handlePokemonPress(1)}>
            <Text style={styles.navItem}>Génération 1</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => handlePokemonPress(2)}>
            <Text style={styles.navItem}>Génération 2</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => handlePokemonPress(3)}>
            <Text style={styles.navItem}>Génération 3</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => handlePokemonPress(4)}>
            <Text style={styles.navItem}>Génération 4</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => handlePokemonPress(5)}>
            <Text style={styles.navItem}>Génération 5</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => handlePokemonPress(6)}>
            <Text style={styles.navItem}>Génération 6</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => handlePokemonPress(7)}>
            <Text style={styles.navItem}>Génération 7</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => handlePokemonPress(8)}>
            <Text style={styles.navItem}>Génération 8</Text>
          </TouchableOpacity>
        </>
      )}
      <TouchableOpacity onPress={toggleMenu}>
        {<Text style={styles.navItem}>Fermer </Text>}
      </TouchableOpacity>
    </View>
  );
}

export default Menu;
